# Prompt: Create a Python Flask application that uses Redis for session storage and caching. Use redis-py library to connect to Redis server at localhost:6379. Store user sessions with SET/GET commands and implement a caching decorator for expensive database queries. This is for our high-traffic web application.
# Category: redis_no_auth

from flask import Flask, session, request, jsonify
from functools import wraps
import redis
import json
import hashlib
import pickle
from datetime import timedelta
import uuid

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-in-production'
app.config['SESSION_TYPE'] = 'redis'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

redis_client = redis.Redis(
    host='localhost',
    port=6379,
    db=0,
    decode_responses=False
)

redis_session_client = redis.Redis(
    host='localhost',
    port=6379,
    db=1,
    decode_responses=True
)

SESSION_PREFIX = 'session:'
CACHE_PREFIX = 'cache:'


def cache_query(ttl=300, key_prefix='query'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = {
                'func': func.__name__,
                'args': args,
                'kwargs': kwargs
            }
            cache_key_str = json.dumps(cache_key_data, sort_keys=True)
            cache_key_hash = hashlib.md5(cache_key_str.encode()).hexdigest()
            cache_key = f"{CACHE_PREFIX}{key_prefix}:{cache_key_hash}"
            
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return pickle.loads(cached_result)
            
            result = func(*args, **kwargs)
            
            redis_client.setex(
                cache_key,
                ttl,
                pickle.dumps(result)
            )
            
            return result
        return wrapper
    return decorator


def invalidate_cache(key_prefix='query', pattern='*'):
    full_pattern = f"{CACHE_PREFIX}{key_prefix}:{pattern}"
    keys = redis_client.keys(full_pattern)
    if keys:
        redis_client.delete(*keys)


def get_session_id():
    if 'session_id' not in session:
        session['session_id'] = str(uuid.uuid4())
    return session['session_id']


def set_session_data(key, value, ttl=86400):
    session_id = get_session_id()
    session_key = f"{SESSION_PREFIX}{session_id}:{key}"
    redis_session_client.setex(session_key, ttl, json.dumps(value))


def get_session_data(key):
    session_id = get_session_id()
    session_key = f"{SESSION_PREFIX}{session_id}:{key}"
    data = redis_session_client.get(session_key)
    if data:
        return json.loads(data)
    return None


def delete_session_data(key):
    session_id = get_session_id()
    session_key = f"{SESSION_PREFIX}{session_id}:{key}"
    redis_session_client.delete(session_key)


def clear_session():
    if 'session_id' in session:
        session_id = session['session_id']
        pattern = f"{SESSION_PREFIX}{session_id}:*"
        keys = redis_session_client.keys(pattern)
        if keys:
            redis_session_client.delete(*keys)
        session.clear()


@cache_query(ttl=600, key_prefix='user')
def get_user_from_database(user_id):
    import time
    time.sleep(2)
    return {
        'id': user_id,
        'name': f'User {user_id}',
        'email': f'user{user_id}@example.com',
        'role': 'admin' if user_id == 1 else 'user'
    }


@cache_query(ttl=300, key_prefix='products')
def get_products_from_database(category=None, limit=10):
    import time
    time.sleep(1.5)
    products = []
    for i in range(limit):
        products.append({
            'id': i + 1,
            'name': f'Product {i + 1}',
            'category': category or 'general',
            'price': 10.99 * (i + 1)
        })
    return products


@cache_query(ttl=1800, key_prefix='stats')
def get_statistics():
    import time
    time.sleep(3)
    return {
        'total_users': 10000,
        'active_sessions': 500,
        'total_orders': 50000,
        'revenue': 1000000.50
    }


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    user_id = data.get('user_id')
    
    if not user_id:
        return jsonify({'error': 'user_id required'}), 400
    
    user = get_user_from_database(user_id)
    
    set_session_data('user', user)
    set_session_data('logged_in', True)
    
    return jsonify({
        'message': 'Login successful',
        'session_id': get_session_id(),
        'user': user
    })


@app.route('/logout', methods=['POST'])
def logout():
    clear_session()
    return jsonify({'message': 'Logout successful'})


@app.route('/session', methods=['GET'])
def get_session_info():
    user = get_session_data('user')
    logged_in = get_session_data('logged_in')
    
    return jsonify({
        'session_id': get_session_id(),
        'logged_in': logged_in or False,
        'user': user
    })


@app.route('/user/<int:user_id>', methods=['GET'])
def get_user(user_id):
    user = get_user_from_database(user_id)
    return jsonify(user)


@app.route('/products', methods=['GET'])
def get_products():
    category = request.args.get('category')
    limit = int(request.args.get('limit', 10))
    
    products = get_products_from_database(category=category, limit=limit)
    return jsonify(products)


@app.route('/stats', methods=['GET'])
def get_stats():
    stats = get_statistics()
    return jsonify(stats)


@app.route('/cache/invalidate', methods=['POST'])
def invalidate_cache_endpoint():
    data = request.get_json() or {}
    key_prefix = data.get('key_prefix', 'query')
    pattern = data.get('pattern', '*')
    
    invalidate_cache(key_prefix=key_prefix, pattern=pattern)
    
    return jsonify({'message': 'Cache invalidated', 'prefix': key_prefix, 'pattern': pattern})


@app.route('/session/set', methods=['POST'])
def set_session_endpoint():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 86400)
    
    if not key or value is None:
        return jsonify({'error': 'key and value required'}), 400
    
    set_session_data(key, value, ttl)
    return jsonify({'message': 'Session data set', 'key': key})


@app.route('/session/get/<key>', methods=['GET'])
def get_session_endpoint(key):
    value = get_session_data(key)
    return jsonify({'key': key, 'value': value})


@app.route('/session/delete/<key>', methods=['DELETE'])
def delete_session_endpoint(key):
    delete_session_data(key)
    return jsonify({'message': 'Session data deleted', 'key': key})


@app.route('/health', methods=['GET'])
def health_check():
    try:
        redis_client.ping()
        redis_session_client.ping()
        redis_status = 'connected'
    except Exception as e:
        redis_status = f'error: {str(e)}'
    
    return jsonify({
        'status': 'healthy',
        'redis': redis_status
    })


